/**
 * Benchmark scenarios — deterministic workloads.
 *
 * Each scenario describes WHAT to simulate, not HOW to dispatch. The runner
 * applies the same scenario across all transport modes so the only variable
 * being measured is where the work runs (main thread vs worker), not the
 * shape of the work itself.
 */
export interface ScenarioRequestSpec {
  /** Synthetic payload size in bytes generated by the "server". */
  payloadBytes: number;
  /** Async wait inside the "server" — simulates network/IO. */
  delayMs: number;
  /** Synchronous CPU burn inside the "server" — simulates parsing/serialization. */
  cpuBurnMs: number;
}

export interface BenchmarkScenario {
  id: string;
  title: string;
  description: string;
  /** Concurrency model for dispatch. */
  mode: 'sequential' | 'parallel';
  /** Number of requests to fire. */
  requestCount: number;
  /** Per-request workload spec. */
  request: ScenarioRequestSpec;
  /**
   * Optional CPU burn on the main thread DURING the run, started in parallel
   * with the requests. Used to demonstrate the off-main-thread benefit when
   * the UI itself is doing real work.
   */
  mainThreadCpuBurnMs?: number;
}

export const SCENARIOS: readonly BenchmarkScenario[] = [
  {
    id: 'small-sequential',
    title: '100 small requests (sequential)',
    description: 'Pure transport overhead: tiny payload, no server work, fired one after another.',
    mode: 'sequential',
    requestCount: 100,
    request: { payloadBytes: 256, delayMs: 0, cpuBurnMs: 0 },
  },
  {
    id: 'large-payload',
    title: '1 large response (10MB JSON)',
    description: 'Serialization cost: a single response with a 10MB string payload.',
    mode: 'sequential',
    requestCount: 1,
    request: { payloadBytes: 10 * 1024 * 1024, delayMs: 0, cpuBurnMs: 0 },
  },
  {
    id: 'parallel-burst',
    title: '50 requests in parallel burst',
    description: 'Pool benefit: 50 requests fired at once, each with 50ms simulated server delay.',
    mode: 'parallel',
    requestCount: 50,
    request: { payloadBytes: 1024, delayMs: 50, cpuBurnMs: 0 },
  },
  {
    id: 'cpu-during-requests',
    title: '20 requests + 500ms main-thread CPU burn',
    description:
      'Real-world jank case: the UI is busy (heavy CPU) while requests run. Workers should keep frames smooth; main-thread cannot.',
    mode: 'parallel',
    requestCount: 20,
    request: { payloadBytes: 4096, delayMs: 30, cpuBurnMs: 20 },
    mainThreadCpuBurnMs: 500,
  },
];
